#!/usr/bin/env python3
"""
inference-server-gkq-gpu.py (ADDITIVE — thin GPU-wired copy)

Imports the UNMODIFIED inference-server-gkq.py and monkey-patches
MemoryResidentWeightCache._reconstruct_layer so that the weight
reconstruction (W = U @ diag(sigma) @ Vt) runs on the GPU via the
NVRTC-compiled sm_61 kernel (gkq_gpu_binding), instead of NumPy on CPU.

Everything else (loader, LRU GPU cache, FastAPI routes, /infer) is the
original server. Launch:

  WEIGHTS_PATH=.../rknots/llama-gkq.knot GPU_CACHE_SIZE_MB=2000 PORT=8000 \
      python3 inference-server-gkq-gpu.py

The original file and the original .cu are untouched.
"""
import os, sys, importlib.util, logging
import numpy as np

HERE = os.path.dirname(os.path.abspath(__file__))
sys.path.insert(0, HERE)

# import the dash-named server module under a clean name
_spec = importlib.util.spec_from_file_location(
    "inference_server_gkq", os.path.join(HERE, "inference-server-gkq.py"))
srv = importlib.util.module_from_spec(_spec)
_spec.loader.exec_module(srv)

import gkq_gpu_binding as gpu

logger = logging.getLogger("gkq-gpu")

_orig_reconstruct = srv.MemoryResidentWeightCache._reconstruct_layer


def _reconstruct_layer_gpu(self, layer_id):
    """GPU reconstruction; falls back to original NumPy on any GPU failure."""
    layer_key = f"layer_{layer_id}"
    try:
        q = self.quantized_weights[layer_key]
        m = self.metadata[layer_key]
        W = gpu.reconstruct_layer_gpu(q, m)
        if not hasattr(self, "_gpu_reconstructions"):
            self._gpu_reconstructions = 0
        self._gpu_reconstructions += 1
        return np.ascontiguousarray(W, dtype=np.float32)
    except Exception as e:  # honest fallback, logged loudly
        logger.error(f"GPU reconstruct failed for {layer_key}: {e}; CPU fallback")
        return _orig_reconstruct(self, layer_id)


# Wire the GPU path in.
srv.MemoryResidentWeightCache._reconstruct_layer = _reconstruct_layer_gpu

# Expose a tiny extra endpoint to confirm GPU reconstructions are happening.
@srv.app.get("/gpu-stats")
async def gpu_stats():
    wc = srv.weight_cache
    n = getattr(wc, "_gpu_reconstructions", 0) if wc else 0
    return {"gpu_reconstructions": n, "reconstruct_fn": srv.MemoryResidentWeightCache._reconstruct_layer.__name__}

app = srv.app  # uvicorn target

if __name__ == "__main__":
    logging.basicConfig(level=logging.INFO,
                        format="%(asctime)s [%(name)s] %(levelname)s: %(message)s")
    import uvicorn
    port = int(os.getenv("PORT", "8000"))
    logger.info(f"GPU-wired GKQ server on :{port} "
                f"(_reconstruct_layer -> {srv.MemoryResidentWeightCache._reconstruct_layer.__name__})")
    # warm-compile the kernel before serving
    try:
        gpu.get_reconstructor()
        logger.info("NVRTC sm_61 kernel compiled & module loaded")
    except Exception as e:
        logger.error(f"kernel warmup failed: {e}")
    uvicorn.run(app, host="0.0.0.0", port=port, workers=1, reload=False)
